const query = $("Webhook").first().json.query;

const broker_id = query.broker_id;
const token = query.token;

const brokers = $items("Sheets — Leer brokers");

const broker = brokers.find(b => 
  b.json.broker_id === broker_id &&
  String(b.json.token_admin) === String(token)
);

if (!broker) {
  throw new Error("No autorizado");
}

return [
  {
    json: {
      broker_id
    }
  }
];

const broker_id = $("Validar acceso").first().json.broker_id;

const leads = $input.all();

const filtrados = leads
  .filter(item => item.json.broker_id === broker_id)
  .sort((a, b) => Number(b.json.row_number || 0) - Number(a.json.row_number || 0))
  .slice(0, 10);

return filtrados.map(item => ({
  json: item.json
}));
